require('dotenv/config');
const { neon } = require('@neondatabase/serverless');

async function getLatestAnalyses() {
    const sql = neon(process.env.DATABASE_URL);
    const results = await sql`SELECT id, weapon_id, scope_id, distance, stability_score as stability, vertical_control as vci, horizontal_noise as noise, recoil_response_ms as response, drift_bias, full_result FROM analysis_sessions ORDER BY created_at DESC LIMIT 5`;

    const fs = require('fs');
    fs.writeFileSync('analyses_dump.json', JSON.stringify(results, null, 2));
    console.log('Saved to analyses_dump.json');
}

getLatestAnalyses().catch(console.error);

/**
 * Analysis Client — Upload de clip, seleção de arma/mira, e pipeline de análise.
 */

'use client';

import { useState, useCallback, useRef, useMemo } from 'react';
import { validateAndPrepareVideo, releaseVideoUrl, extractFrames, trackCrosshair, buildTrajectory, calculateSprayMetrics, runDiagnostics, generateSensitivityRecommendation, generateCoaching, scanInventory, type InventoryScanResult } from '@/core';
import type { VideoMetadata } from '@/core';
import type { AnalysisResult } from '@/types/engine';
import { WEAPON_LIST, getWeapon, SCOPE_LIST } from '@/game/pubg';
import { ResultsDashboard } from './results-dashboard';
import { saveAnalysisResult } from '@/actions/history';
import type { PlayerProfile } from '@/db/schema';
import styles from './analysis.module.css';

type AnalysisStep = 'upload' | 'settings' | 'processing' | 'done' | 'error';
type ProcessingPhase = 'extracting' | 'tracking' | 'calculating' | 'diagnosing' | 'done';

interface Props {
    readonly profile: PlayerProfile;
}

export function AnalysisClient({ profile }: Props): React.JSX.Element {
    const [step, setStep] = useState<AnalysisStep>('upload');
    const [video, setVideo] = useState<VideoMetadata | null>(null);
    const [weaponId, setWeaponId] = useState('m416');
    const [scopeId, setScopeId] = useState('red-dot');
    const [distance, setDistance] = useState(30);
    const [markers, setMarkers] = useState<{ id: string, time: number }[]>([{ id: crypto.randomUUID(), time: 0 }]);
    const videoRef = useRef<HTMLVideoElement>(null);
    const [phase, setPhase] = useState<ProcessingPhase>('extracting');
    const [progress, setProgress] = useState(0);
    const [error, setError] = useState<string | null>(null);
    const [result, setResult] = useState<AnalysisResult | null>(null);
    const [dragActive, setDragActive] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const weaponsByCategory = useMemo(() => {
        const grouped: Record<string, typeof WEAPON_LIST[number][]> = {};
        for (const w of WEAPON_LIST) {
            if (!grouped[w.category]) grouped[w.category] = [];
            grouped[w.category]!.push(w);
        }
        return grouped;
    }, []);

    const handleFile = useCallback(async (file: File) => {
        setError(null);
        const result = await validateAndPrepareVideo(file);
        if (!result.valid) {
            setError(result.error.message);
            return;
        }
        setVideo(result.metadata);
        setMarkers([{ id: crypto.randomUUID(), time: 0 }]);
        setStep('settings');
    }, []);

    const addMarker = useCallback(() => {
        setMarkers(prev => [...prev, { id: crypto.randomUUID(), time: video?.duration ? video.duration / 2 : 0 }]);
    }, [video]);

    const removeMarker = useCallback((id: string) => {
        setMarkers(prev => prev.length > 1 ? prev.filter(m => m.id !== id) : prev);
    }, []);

    const updateMarker = useCallback((id: string, time: number) => {
        setMarkers(prev => prev.map(m => m.id === id ? { ...m, time } : m));
        if (videoRef.current) videoRef.current.currentTime = time;
    }, []);

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setDragActive(false);
        const file = e.dataTransfer.files[0];
        if (file) void handleFile(file);
    }, [handleFile]);

    const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) void handleFile(file);
    }, [handleFile]);

    const handleAnalyze = useCallback(async () => {
        if (!video) return;
        setStep('processing');
        setPhase('extracting');
        setProgress(0);

        try {
            const weapon = getWeapon(weaponId);
            if (!weapon) throw new Error('Arma não encontrada');

            // 1. [Elite Workflow] Scan for Inventory (Tab) in the first 2 seconds
            // This helps auto-detect attachments and active slot.
            const scanFrames = await extractFrames(video.url, 10, 0, 2);
            const invResult = scanInventory(scanFrames);
            if (invResult.found) {
                console.log('Inventory detected!', invResult);
                // Implementation for auto-updating weapon/attachments will follow
            }

            const subSessions: AnalysisResult[] = [];
            const stepIncrement = 100 / markers.length;

            for (let i = 0; i < markers.length; i++) {
                const marker = markers[i]!;
                const startTime = marker.time;

                setPhase('extracting');
                // Calculate EXACT spray duration
                const expectedDurationSecs = (weapon.magazineSize * weapon.msPerShot / 1000) + 0.5;

                const frames = await extractFrames(video.url, Math.min(video.fps, 30), startTime, expectedDurationSecs, (p) => {
                    setProgress((i * stepIncrement) + (p.percent * 0.3 * (stepIncrement / 100)));
                });

                setPhase('tracking');
                const tracking = trackCrosshair(frames);

                setPhase('calculating');
                const trajectory = buildTrajectory(tracking, weapon);
                const monitorWidth = parseInt(profile.monitorResolution.split('x')[0] || '1920', 10);
                const pixelToDegree = profile.fov / monitorWidth;
                const metrics = calculateSprayMetrics(trajectory, weapon, pixelToDegree);

                setPhase('diagnosing');
                const diagnoses = runDiagnostics(metrics, weapon.category);
                const sensitivity = generateSensitivityRecommendation(
                    metrics, diagnoses,
                    profile.mouseDpi,
                    profile.playStyle,
                    profile.gripStyle,
                    profile.mousepadWidth,
                    profile.scopeSens as Record<string, number>,
                    profile.verticalMultiplier
                );
                const coaching = generateCoaching(diagnoses);

                subSessions.push({
                    id: crypto.randomUUID(),
                    timestamp: new Date(),
                    trajectory,
                    metrics,
                    diagnoses,
                    sensitivity,
                    coaching,
                });

                setProgress((i + 1) * stepIncrement);
            }

            // Aggregate Results with Weighted Average (by Duration)
            const totalDuration = subSessions.reduce((acc, s) => acc + s.trajectory.durationMs, 0) || 1;

            const avgStability = subSessions.reduce((acc, s) => acc + (s.metrics.stabilityScore * s.trajectory.durationMs), 0) / totalDuration;
            const avgVCI = subSessions.reduce((acc, s) => acc + (s.metrics.verticalControlIndex * s.trajectory.durationMs), 0) / totalDuration;
            const avgHNI = subSessions.reduce((acc, s) => acc + (s.metrics.horizontalNoiseIndex * s.trajectory.durationMs), 0) / totalDuration;
            const avgResponse = subSessions.reduce((acc, s) => acc + (s.metrics.initialRecoilResponseMs * s.trajectory.durationMs), 0) / totalDuration;
            const avgConsistency = subSessions.reduce((acc, s) => acc + (s.metrics.consistencyScore * s.trajectory.durationMs), 0) / totalDuration;

            // Average of Phase-based metrics
            const avgBurstVCI = subSessions.reduce((acc, s) => acc + (s.metrics.burstVCI * s.trajectory.durationMs), 0) / totalDuration;
            const avgSustainedVCI = subSessions.reduce((acc, s) => acc + (s.metrics.sustainedVCI * s.trajectory.durationMs), 0) / totalDuration;
            const avgFatigueVCI = subSessions.reduce((acc, s) => acc + (s.metrics.fatigueVCI * s.trajectory.durationMs), 0) / totalDuration;

            const finalMetrics = {
                ...subSessions[0]!.metrics,
                stabilityScore: Math.round(avgStability) as any,
                verticalControlIndex: Number(avgVCI.toFixed(2)),
                horizontalNoiseIndex: Number(avgHNI.toFixed(2)),
                initialRecoilResponseMs: Math.round(avgResponse) as any,
                consistencyScore: Math.round(avgConsistency) as any,
                burstVCI: avgBurstVCI,
                sustainedVCI: avgSustainedVCI,
                fatigueVCI: avgFatigueVCI,
            };

            const finalDiagnoses = runDiagnostics(finalMetrics, weapon.category);
            const finalSens = generateSensitivityRecommendation(
                finalMetrics, finalDiagnoses,
                profile.mouseDpi,
                profile.playStyle,
                profile.gripStyle,
                profile.mousepadWidth,
                profile.scopeSens as Record<string, number>,
                profile.verticalMultiplier
            );

            const finalResult: AnalysisResult = {
                id: crypto.randomUUID(),
                timestamp: new Date(),
                trajectory: subSessions[0]!.trajectory, // Use first as preview
                metrics: finalMetrics,
                diagnoses: finalDiagnoses,
                sensitivity: finalSens,
                coaching: generateCoaching(finalDiagnoses),
                subSessions,
            };

            try {
                await saveAnalysisResult(finalResult, weaponId, scopeId, distance);
            } catch (err) {
                console.error('[saveAnalysisResult]', err);
            }

            setResult(finalResult);
            setStep('done');
        } catch (err) {
            console.error('[Analysis Error]:', err);
            setError(err instanceof Error ? err.message : 'Erro na análise');
            setStep('error');
        }
    }, [video, weaponId, markers, profile, scopeId, distance]);

    const handleReset = useCallback(() => {
        if (video) releaseVideoUrl(video.url);
        setVideo(null);
        setStep('upload');
        setResult(null);
        setError(null);
    }, [video]);

    const phaseLabels: Record<ProcessingPhase, string> = {
        extracting: '🎞️ Extraindo frames...',
        tracking: '🎯 Rastreando mira...',
        calculating: '📊 Calculando métricas...',
        diagnosing: '🧠 Diagnosticando...',
        done: '✅ Análise concluída!',
    };

    // ═══ Upload Step ═══
    if (step === 'upload') {
        return (
            <div>
                <div
                    className={`${styles.dropzone} ${dragActive ? styles.dropzoneActive : ''}`}
                    onDragOver={(e) => { e.preventDefault(); setDragActive(true); }}
                    onDragLeave={() => setDragActive(false)}
                    onDrop={handleDrop}
                    onClick={() => fileInputRef.current?.click()}
                    role="button"
                    tabIndex={0}
                    aria-label="Área de upload de vídeo"
                >
                    <div className={styles.dropzoneIcon}>🎬</div>
                    <h3>Solte seu clip aqui</h3>
                    <p>MP4 ou WebM, 5-15 segundos, até 50MB</p>
                    <button className="btn btn-primary" type="button">Escolher Arquivo</button>
                    <input
                        ref={fileInputRef}
                        type="file"
                        accept="video/mp4,video/webm"
                        onChange={handleInputChange}
                        style={{ display: 'none' }}
                        aria-hidden="true"
                    />
                </div>
                {error && <div className={styles.error}>❌ {error}</div>}
            </div>
        );
    }

    // ═══ Settings Step ═══
    if (step === 'settings' && video) {
        return (
            <div className="animate-fade-in">
                <div className={`glass-card ${styles.videoPreview}`}>
                    <video ref={videoRef} src={video.url} controls className={styles.video} />
                    <div className={styles.videoMeta}>
                        <span className="badge badge-info">{video.width}×{video.height}</span>
                        <span className="badge badge-info">{Math.round(video.duration)}s</span>
                        <span className="badge badge-info">{video.fps} FPS</span>
                    </div>
                </div>

                <div className={`glass-card ${styles.settingsForm}`}>
                    <h3>Configurações da Análise</h3>
                    <div className={styles.settingsGrid}>
                        <div className={styles.field}>
                            <label className="input-label" htmlFor="weapon">Arma *</label>
                            <select id="weapon" className="input select" value={weaponId} onChange={e => setWeaponId(e.target.value)}>
                                {Object.entries(weaponsByCategory).map(([cat, weapons]) => (
                                    <optgroup key={cat} label={cat.toUpperCase()}>
                                        {weapons.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
                                    </optgroup>
                                ))}
                            </select>
                        </div>
                        <div className={styles.field}>
                            <label className="input-label" htmlFor="scope">Mira *</label>
                            <select id="scope" className="input select" value={scopeId} onChange={e => setScopeId(e.target.value)}>
                                {SCOPE_LIST.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                        <div className={styles.field}>
                            <label className="input-label" htmlFor="dist">Distância (m) *</label>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-md)' }}>
                                <input id="dist" type="range" className="slider" min={10} max={300} value={distance} onChange={e => setDistance(Number(e.target.value))} />
                                <span style={{ fontFamily: 'var(--font-mono)', color: 'var(--color-accent-primary)', minWidth: '40px' }}>{distance}m</span>
                            </div>
                        </div>
                        <div className={styles.field} style={{ gridColumn: '1 / -1' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                                <div>
                                    <label className="input-label">Identificação de Sprays *</label>
                                    <p style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)', lineHeight: 1.4 }}>
                                        Adicione marcadores no exato frame em que cada burst começa. A IA analisará todos e fará a média.
                                    </p>
                                </div>
                                <button className="btn btn-ghost btn-sm" onClick={addMarker}>+ Adicionar Spray</button>
                            </div>

                            <div className={styles.markersList}>
                                {markers.map((m, idx) => (
                                    <div key={m.id} className={styles.markerRow}>
                                        <span className={styles.markerLabel}>Spray #{idx + 1}</span>
                                        <input
                                            type="range"
                                            className="slider"
                                            min={0}
                                            max={video.duration}
                                            step={0.01}
                                            value={m.time}
                                            onChange={e => updateMarker(m.id, Number(e.target.value))}
                                            style={{ flex: 1 }}
                                        />
                                        <span className={styles.markerTime}>{m.time.toFixed(2)}s</span>
                                        <button
                                            className={styles.removeMarker}
                                            onClick={() => removeMarker(m.id)}
                                            disabled={markers.length <= 1}
                                            title="Remover"
                                        >
                                            ✕
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className={styles.settingsActions}>
                        <button className="btn btn-ghost" onClick={handleReset}>← Trocar Clip</button>
                        <button className="btn btn-primary btn-lg" onClick={handleAnalyze}>🚀 Iniciar Análise</button>
                    </div>
                </div>
            </div>
        );
    }

    // ═══ Processing Step ═══
    if (step === 'processing') {
        return (
            <div className={`glass-card ${styles.processing}`}>
                <div className={styles.processingSpinner} />
                <h3>{phaseLabels[phase]}</h3>
                <div className="progress-bar" style={{ maxWidth: '400px', margin: '0 auto' }}>
                    <div className="progress-bar-fill" style={{ width: `${progress}%` }} />
                </div>
                <p style={{ fontFamily: 'var(--font-mono)', fontSize: 'var(--text-sm)', color: 'var(--color-text-muted)' }}>
                    {Math.round(progress)}%
                </p>
            </div>
        );
    }

    // ═══ Error Step ═══
    if (step === 'error') {
        return (
            <div className={`glass-card ${styles.processing}`}>
                <div style={{ fontSize: 'var(--text-4xl)', marginBottom: 'var(--space-lg)' }}>❌</div>
                <h3>Erro na Análise</h3>
                <p>{error}</p>
                <button className="btn btn-primary" onClick={handleReset} style={{ marginTop: 'var(--space-xl)' }}>Tentar Novamente</button>
            </div>
        );
    }

    // ═══ Results Step ═══
    if (step === 'done' && result) {
        return (
            <div className="animate-fade-in">
                <div className={styles.resultHeader}>
                    <h2>Resultado da Análise</h2>
                    <button className="btn btn-ghost" onClick={handleReset}>← Nova Análise</button>
                </div>
                <ResultsDashboard result={result} />
            </div>
        );
    }

    return <div />;
}

/**
 * Spray Visualization Component
 * Renders the player's spray trajectory compared to the ideal pattern.
 */

'use client';

import { useEffect, useRef } from 'react';
import type { SprayTrajectory, DisplacementVector } from '@/types/engine';

interface Props {
    readonly trajectory: SprayTrajectory;
    readonly width?: number;
    readonly height?: number;
    readonly showIdeal?: boolean;
}

export function SprayVisualization({
    trajectory,
    width = 400,
    height = 400,
    showIdeal = true
}: Props): React.JSX.Element {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Clear
        ctx.clearRect(0, 0, width, height);

        // Draw Grid
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
        ctx.lineWidth = 1;
        for (let i = 0; i <= 10; i++) {
            const x = (i / 10) * width;
            const y = (i / 10) * height;
            ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, height); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(width, y); ctx.stroke();
        }

        const centerX = width / 2;
        const centerY = height / 2;

        // Center Crosshair / Target
        ctx.strokeStyle = 'rgba(0, 240, 255, 0.6)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        // Cross
        ctx.moveTo(centerX - 15, centerY); ctx.lineTo(centerX + 15, centerY);
        ctx.moveTo(centerX, centerY - 15); ctx.lineTo(centerX, centerY + 15);
        ctx.stroke();

        // Circle
        ctx.beginPath();
        ctx.arc(centerX, centerY, 5, 0, Math.PI * 2);
        ctx.stroke();

        let currentX = centerX;
        let currentY = centerY;

        // Draw Player Trajectory
        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        ctx.strokeStyle = 'rgba(255, 107, 0, 1)';
        ctx.lineWidth = 2;
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';

        const scale = 8; // Scale pixels for visibility (increased for better detail)

        // Shadow/Glow for trajectory
        ctx.shadowBlur = 10;
        ctx.shadowColor = 'rgba(255, 107, 0, 0.5)';

        trajectory.displacements.forEach((d) => {
            currentX += d.dx * scale;
            currentY += d.dy * scale;
            ctx.lineTo(currentX, currentY);
        });
        ctx.stroke();

        // Reset shadow
        ctx.shadowBlur = 0;

        // Draw Shots (Impact points with glow)
        currentX = centerX;
        currentY = centerY;
        trajectory.displacements.forEach((d) => {
            currentX += d.dx * scale;
            currentY += d.dy * scale;

            ctx.fillStyle = 'rgba(255, 255, 255, 1)';
            ctx.shadowBlur = 5;
            ctx.shadowColor = '#fff';

            ctx.beginPath();
            ctx.arc(currentX, currentY, 2.5, 0, Math.PI * 2);
            ctx.fill();
        });
        ctx.shadowBlur = 0;

    }, [trajectory, width, height, showIdeal]);

    return (
        <canvas
            ref={canvasRef}
            width={width}
            height={height}
            style={{ width: '100%', height: '100%', display: 'block' }}
        />
    );
}

/**
 * Error Page — Global error boundary com retry e visual glitch.
 */

'use client';

export default function Error({
    error,
    reset,
}: {
    error: Error & { digest?: string };
    reset: () => void;
}): React.JSX.Element {
    return (
        <div
            className="page"
            style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                minHeight: '80vh',
                textAlign: 'center',
                padding: 'var(--space-xl)',
            }}
        >
            <div
                style={{
                    fontSize: '4rem',
                    marginBottom: 'var(--space-lg)',
                }}
                aria-hidden="true"
            >
                ⚠️
            </div>

            <h1 style={{ fontSize: 'var(--text-3xl)', marginBottom: 'var(--space-md)' }}>
                Algo Deu Errado
            </h1>

            <p style={{
                color: 'var(--color-text-secondary)',
                maxWidth: '400px',
                marginBottom: 'var(--space-md)',
            }}>
                Ocorreu um erro inesperado. Tente novamente ou volte à página inicial.
            </p>

            {error.digest && (
                <p style={{
                    fontFamily: 'var(--font-mono)',
                    fontSize: 'var(--text-xs)',
                    color: 'var(--color-text-muted)',
                    marginBottom: 'var(--space-xl)',
                }}>
                    Código: {error.digest}
                </p>
            )}

            <div style={{ display: 'flex', gap: 'var(--space-md)' }}>
                <button
                    onClick={reset}
                    className="btn btn-primary"
                >
                    Tentar Novamente
                </button>
                <a href="/" className="btn btn-secondary">
                    Voltar ao Início
                </a>
            </div>
        </div>
    );
}

/**
 * Profile Wizard — Multi-step form com 6 steps.
 * Client Component para interatividade do formulário.
 */

'use client';

import { useState, useCallback, useMemo } from 'react';
import { saveProfile } from '@/actions/profile';
import type { ProfileActionResult } from '@/actions/profile';
import type { playerProfiles } from '@/db/schema';
import styles from './profile-wizard.module.css';

// ═══════════════════════════════════════════
// Step definitions
// ═══════════════════════════════════════════

const STEPS = [
    { id: 'mouse', label: '🖱️ Mouse', icon: '🖱️' },
    { id: 'mousepad', label: '🟫 Mousepad', icon: '🟫' },
    { id: 'style', label: '🎮 Estilo', icon: '🎮' },
    { id: 'monitor', label: '🖥️ Monitor', icon: '🖥️' },
    { id: 'pubg', label: '⚙️ PUBG', icon: '⚙️' },
    { id: 'physical', label: '📐 Espaço', icon: '📐' },
] as const;

// ═══════════════════════════════════════════
// Default form state
// ═══════════════════════════════════════════

interface FormState {
    mouse: { model: string; sensor: string; dpi: number; pollingRate: number; weightGrams: number; liftOffDistance: number };
    mousepad: { model: string; widthCm: number; heightCm: number; type: string; material: string };
    gripStyle: string;
    playStyle: string;
    monitor: { resolution: string; refreshRate: number; panelType: string };
    pubgSettings: {
        generalSens: number; adsSens: number; fov: number;
        verticalMultiplier: number; mouseAcceleration: boolean;
        scopeSens: Record<string, number>;
    };
    physical: { armLength: string; deskSpaceCm: number };
}

const DEFAULT_FORM: FormState = {
    mouse: { model: '', sensor: '', dpi: 800, pollingRate: 1000, weightGrams: 80, liftOffDistance: 1 },
    mousepad: { model: '', widthCm: 45, heightCm: 40, type: 'control', material: 'cloth' },
    gripStyle: 'claw',
    playStyle: 'hybrid',
    monitor: { resolution: '1920x1080', refreshRate: 144, panelType: 'ips' },
    pubgSettings: {
        generalSens: 50, adsSens: 50, fov: 103, verticalMultiplier: 1.0, mouseAcceleration: false,
        scopeSens: { 'red-dot': 50, '2x': 50, '3x': 50, '4x': 50, '6x': 50, '8x': 50 },
    },
    physical: { armLength: 'medium', deskSpaceCm: 60 },
};

// ═══════════════════════════════════════════
// Component
// ═══════════════════════════════════════════

interface Props {
    readonly initialData?: typeof playerProfiles.$inferSelect | null;
}

export function ProfileWizard({ initialData }: Props): React.JSX.Element {
    const [step, setStep] = useState(0);

    // Hydrate form from initialData or use defaults
    const hydratedForm = useMemo((): FormState => {
        if (!initialData) return DEFAULT_FORM;

        return {
            mouse: {
                model: initialData.mouseModel,
                sensor: initialData.mouseSensor,
                dpi: initialData.mouseDpi,
                pollingRate: initialData.mousePollingRate,
                weightGrams: initialData.mouseWeight,
                liftOffDistance: initialData.mouseLod,
            },
            mousepad: {
                model: initialData.mousepadModel,
                widthCm: initialData.mousepadWidth,
                heightCm: initialData.mousepadHeight,
                type: initialData.mousepadType,
                material: initialData.mousepadMaterial,
            },
            gripStyle: initialData.gripStyle,
            playStyle: initialData.playStyle,
            monitor: {
                resolution: initialData.monitorResolution,
                refreshRate: initialData.monitorRefreshRate,
                panelType: initialData.monitorPanel,
            },
            pubgSettings: {
                generalSens: initialData.generalSens,
                adsSens: initialData.adsSens,
                fov: initialData.fov,
                verticalMultiplier: initialData.verticalMultiplier,
                mouseAcceleration: initialData.mouseAcceleration,
                scopeSens: initialData.scopeSens as Record<string, number>,
            },
            physical: {
                armLength: initialData.armLength as any,
                deskSpaceCm: initialData.deskSpace,
            },
        };
    }, [initialData]);

    const [form, setForm] = useState<FormState>(hydratedForm);
    const [saving, setSaving] = useState(false);
    const [result, setResult] = useState<ProfileActionResult | null>(null);

    const updateField = useCallback(<K extends keyof FormState>(
        section: K,
        field: string,
        value: string | number | boolean
    ): void => {
        setForm(prev => {
            const sectionVal = prev[section];
            if (typeof sectionVal === 'object' && sectionVal !== null) {
                return { ...prev, [section]: { ...sectionVal, [field]: value } };
            }
            return { ...prev, [section]: value };
        });
    }, []);

    const updateScopeSens = useCallback((scope: string, value: number): void => {
        setForm(prev => ({
            ...prev,
            pubgSettings: {
                ...prev.pubgSettings,
                scopeSens: { ...prev.pubgSettings.scopeSens, [scope]: value },
            },
        }));
    }, []);

    const handleSubmit = useCallback(async (): Promise<void> => {
        setSaving(true);
        setResult(null);
        const res = await saveProfile(form);
        setResult(res);
        setSaving(false);
    }, [form]);

    const canGoNext = step < STEPS.length - 1;
    const canGoBack = step > 0;
    const isLastStep = step === STEPS.length - 1;

    return (
        <div className={styles.wizard}>
            {/* Step Indicator */}
            <div className={styles.steps} role="tablist" aria-label="Passos do formulário">
                {STEPS.map((s, i) => (
                    <button
                        key={s.id}
                        className={`${styles.stepBtn} ${i === step ? styles.stepActive : ''} ${i < step ? styles.stepDone : ''}`}
                        onClick={() => setStep(i)}
                        role="tab"
                        aria-selected={i === step}
                        aria-label={`Passo ${i + 1}: ${s.label}`}
                    >
                        <span className={styles.stepIcon}>{s.icon}</span>
                        <span className={styles.stepLabel}>{s.label.split(' ')[1]}</span>
                    </button>
                ))}
            </div>

            {/* Progress bar */}
            <div className="progress-bar" style={{ marginBottom: 'var(--space-xl)' }}>
                <div className="progress-bar-fill" style={{ width: `${((step + 1) / STEPS.length) * 100}%` }} />
            </div>

            {/* Step Content */}
            <div className={`glass-card ${styles.stepContent}`} role="tabpanel">
                {step === 0 && (
                    <div className={styles.fadeIn}>
                        <h3 className={styles.stepTitle}>🖱️ Mouse</h3>
                        <p className={styles.stepDesc}>Dados do seu mouse para calcular a sensibilidade ideal.</p>
                        <div className={styles.formGrid}>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="mouse-model">Modelo *</label>
                                <input id="mouse-model" className="input" placeholder="Ex: Logitech G Pro X Superlight" value={form.mouse.model} onChange={e => updateField('mouse', 'model', e.target.value)} />
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="mouse-sensor">Sensor *</label>
                                <input id="mouse-sensor" className="input" placeholder="Ex: HERO 25K, PAW3395" value={form.mouse.sensor} onChange={e => updateField('mouse', 'sensor', e.target.value)} />
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="mouse-dpi">DPI *</label>
                                <input id="mouse-dpi" type="number" className="input" min={100} max={25600} value={form.mouse.dpi} onChange={e => updateField('mouse', 'dpi', Number(e.target.value))} />
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="mouse-polling">Polling Rate *</label>
                                <select id="mouse-polling" className="input select" value={form.mouse.pollingRate} onChange={e => updateField('mouse', 'pollingRate', Number(e.target.value))}>
                                    <option value={125}>125 Hz</option>
                                    <option value={250}>250 Hz</option>
                                    <option value={500}>500 Hz</option>
                                    <option value={1000}>1000 Hz</option>
                                    <option value={2000}>2000 Hz</option>
                                    <option value={4000}>4000 Hz</option>
                                </select>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="mouse-weight">Peso (gramas) *</label>
                                <input id="mouse-weight" type="number" className="input" min={30} max={200} value={form.mouse.weightGrams} onChange={e => updateField('mouse', 'weightGrams', Number(e.target.value))} />
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="mouse-lod">Lift-off Distance (mm) *</label>
                                <input id="mouse-lod" type="number" className="input" step={0.1} min={0.5} max={3} value={form.mouse.liftOffDistance} onChange={e => updateField('mouse', 'liftOffDistance', Number(e.target.value))} />
                            </div>
                        </div>
                    </div>
                )}

                {step === 1 && (
                    <div className={styles.fadeIn}>
                        <h3 className={styles.stepTitle}>🟫 Mousepad</h3>
                        <p className={styles.stepDesc}>O tamanho e tipo do mousepad definem o range de sensibilidade viável.</p>
                        <div className={styles.formGrid}>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pad-model">Modelo *</label>
                                <input id="pad-model" className="input" placeholder="Ex: Artisan Hien, QcK Heavy" value={form.mousepad.model} onChange={e => updateField('mousepad', 'model', e.target.value)} />
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pad-type">Tipo *</label>
                                <select id="pad-type" className="input select" value={form.mousepad.type} onChange={e => updateField('mousepad', 'type', e.target.value)}>
                                    <option value="speed">Speed</option>
                                    <option value="control">Control</option>
                                    <option value="hybrid">Híbrido</option>
                                </select>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pad-width">Largura (cm) *</label>
                                <input id="pad-width" type="number" className="input" min={10} max={120} value={form.mousepad.widthCm} onChange={e => updateField('mousepad', 'widthCm', Number(e.target.value))} />
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pad-height">Altura (cm) *</label>
                                <input id="pad-height" type="number" className="input" min={10} max={60} value={form.mousepad.heightCm} onChange={e => updateField('mousepad', 'heightCm', Number(e.target.value))} />
                            </div>
                            <div className={styles.field} style={{ gridColumn: 'span 2' }}>
                                <label className="input-label" htmlFor="pad-material">Material *</label>
                                <select id="pad-material" className="input select" value={form.mousepad.material} onChange={e => updateField('mousepad', 'material', e.target.value)}>
                                    <option value="cloth">Tecido (Cloth)</option>
                                    <option value="hard">Rígido (Hard)</option>
                                    <option value="glass">Vidro (Glass)</option>
                                </select>
                            </div>
                        </div>
                    </div>
                )}

                {step === 2 && (
                    <div className={styles.fadeIn}>
                        <h3 className={styles.stepTitle}>🎮 Estilo de Jogo</h3>
                        <p className={styles.stepDesc}>Seu grip e estilo influenciam diretamente na sensibilidade recomendada.</p>

                        <div className={styles.optionSection}>
                            <label className="input-label">Grip Style *</label>
                            <div className={styles.optionGrid}>
                                {(['palm', 'claw', 'fingertip', 'hybrid'] as const).map(g => (
                                    <button key={g} type="button"
                                        className={`${styles.optionCard} ${form.gripStyle === g ? styles.optionActive : ''}`}
                                        onClick={() => setForm(prev => ({ ...prev, gripStyle: g }))}
                                        aria-pressed={form.gripStyle === g}
                                    >
                                        <span className={styles.optionEmoji}>{g === 'palm' ? '🤚' : g === 'claw' ? '🦀' : g === 'fingertip' ? '☝️' : '🔀'}</span>
                                        <span className={styles.optionName}>{g.charAt(0).toUpperCase() + g.slice(1)}</span>
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className={styles.optionSection}>
                            <label className="input-label">Play Style *</label>
                            <div className={styles.optionGrid}>
                                {(['arm', 'wrist', 'hybrid'] as const).map(p => (
                                    <button key={p} type="button"
                                        className={`${styles.optionCard} ${form.playStyle === p ? styles.optionActive : ''}`}
                                        onClick={() => setForm(prev => ({ ...prev, playStyle: p }))}
                                        aria-pressed={form.playStyle === p}
                                    >
                                        <span className={styles.optionEmoji}>{p === 'arm' ? '💪' : p === 'wrist' ? '✊' : '🔀'}</span>
                                        <span className={styles.optionName}>{p === 'arm' ? 'Arm Aimer' : p === 'wrist' ? 'Wrist Aimer' : 'Híbrido'}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                    </div>
                )}

                {step === 3 && (
                    <div className={styles.fadeIn}>
                        <h3 className={styles.stepTitle}>🖥️ Monitor</h3>
                        <p className={styles.stepDesc}>Resolução e refresh rate afetam o FOV e a fluidez do tracking.</p>
                        <div className={styles.formGrid}>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="monitor-res">Resolução *</label>
                                <select id="monitor-res" className="input select" value={form.monitor.resolution} onChange={e => updateField('monitor', 'resolution', e.target.value)}>
                                    <option value="1920x1080">1920×1080 (Full HD)</option>
                                    <option value="2560x1440">2560×1440 (2K)</option>
                                    <option value="3840x2160">3840×2160 (4K)</option>
                                    <option value="2560x1080">2560×1080 (UW)</option>
                                    <option value="3440x1440">3440×1440 (UW 2K)</option>
                                </select>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="monitor-hz">Refresh Rate *</label>
                                <select id="monitor-hz" className="input select" value={form.monitor.refreshRate} onChange={e => updateField('monitor', 'refreshRate', Number(e.target.value))}>
                                    <option value={60}>60 Hz</option>
                                    <option value={75}>75 Hz</option>
                                    <option value={144}>144 Hz</option>
                                    <option value={165}>165 Hz</option>
                                    <option value={240}>240 Hz</option>
                                    <option value={360}>360 Hz</option>
                                </select>
                            </div>
                            <div className={styles.field} style={{ gridColumn: 'span 2' }}>
                                <label className="input-label" htmlFor="monitor-panel">Tipo de Painel *</label>
                                <select id="monitor-panel" className="input select" value={form.monitor.panelType} onChange={e => updateField('monitor', 'panelType', e.target.value)}>
                                    <option value="ips">IPS</option>
                                    <option value="tn">TN</option>
                                    <option value="va">VA</option>
                                </select>
                            </div>
                        </div>
                    </div>
                )}

                {step === 4 && (
                    <div className={styles.fadeIn}>
                        <h3 className={styles.stepTitle}>⚙️ Configurações PUBG</h3>
                        <p className={styles.stepDesc}>Suas configurações atuais in-game. A IA vai comparar com o ideal.</p>
                        <div className={styles.formGrid}>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pubg-gen">Sensibilidade Geral *</label>
                                <div className={styles.sliderRow}>
                                    <input id="pubg-gen" type="range" className="slider" min={1} max={100} value={form.pubgSettings.generalSens} onChange={e => updateField('pubgSettings', 'generalSens', Number(e.target.value))} />
                                    <span className={styles.sliderValue}>{form.pubgSettings.generalSens}</span>
                                </div>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pubg-ads">Sensibilidade ADS *</label>
                                <div className={styles.sliderRow}>
                                    <input id="pubg-ads" type="range" className="slider" min={1} max={100} value={form.pubgSettings.adsSens} onChange={e => updateField('pubgSettings', 'adsSens', Number(e.target.value))} />
                                    <span className={styles.sliderValue}>{form.pubgSettings.adsSens}</span>
                                </div>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pubg-fov">FOV *</label>
                                <div className={styles.sliderRow}>
                                    <input id="pubg-fov" type="range" className="slider" min={80} max={103} value={form.pubgSettings.fov} onChange={e => updateField('pubgSettings', 'fov', Number(e.target.value))} />
                                    <span className={styles.sliderValue}>{form.pubgSettings.fov}</span>
                                </div>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="pubg-vmult">Multiplicador Vertical *</label>
                                <div className={styles.sliderRow}>
                                    <input id="pubg-vmult" type="range" className="slider" min={50} max={150} value={form.pubgSettings.verticalMultiplier * 100} onChange={e => updateField('pubgSettings', 'verticalMultiplier', Number(e.target.value) / 100)} />
                                    <span className={styles.sliderValue}>{form.pubgSettings.verticalMultiplier.toFixed(2)}</span>
                                </div>
                            </div>

                            {/* Scope sensitivities */}
                            <div className={styles.field} style={{ gridColumn: 'span 2' }}>
                                <label className="input-label">Sensibilidade por Mira *</label>
                                <div className={styles.scopeGrid}>
                                    {Object.entries(form.pubgSettings.scopeSens).map(([scope, val]) => (
                                        <div key={scope} className={styles.scopeItem}>
                                            <span className={styles.scopeLabel}>{scope.replace('-', ' ').toUpperCase()}</span>
                                            <input type="range" className="slider" min={1} max={100} value={val} onChange={e => updateScopeSens(scope, Number(e.target.value))} aria-label={`Sensibilidade ${scope}`} />
                                            <span className={styles.scopeValue}>{val}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            <div className={styles.field} style={{ gridColumn: 'span 2' }}>
                                <label className={styles.checkboxLabel}>
                                    <input type="checkbox" checked={form.pubgSettings.mouseAcceleration} onChange={e => updateField('pubgSettings', 'mouseAcceleration', e.target.checked)} />
                                    <span>Aceleração do Mouse ativada</span>
                                </label>
                            </div>
                        </div>
                    </div>
                )}

                {step === 5 && (
                    <div className={styles.fadeIn}>
                        <h3 className={styles.stepTitle}>📐 Espaço Físico</h3>
                        <p className={styles.stepDesc}>Espaço disponível para movimentar o mouse e comprimento do braço.</p>
                        <div className={styles.formGrid}>
                            <div className={styles.field}>
                                <label className="input-label">Comprimento do Braço *</label>
                                <div className={styles.optionGrid}>
                                    {(['short', 'medium', 'long'] as const).map(a => (
                                        <button key={a} type="button"
                                            className={`${styles.optionCard} ${form.physical.armLength === a ? styles.optionActive : ''}`}
                                            onClick={() => updateField('physical', 'armLength', a)}
                                            aria-pressed={form.physical.armLength === a}
                                        >
                                            <span className={styles.optionName}>{a === 'short' ? 'Curto' : a === 'medium' ? 'Médio' : 'Longo'}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="desk-space">Espaço na Mesa (cm) *</label>
                                <div className={styles.sliderRow}>
                                    <input id="desk-space" type="range" className="slider" min={20} max={200} value={form.physical.deskSpaceCm} onChange={e => updateField('physical', 'deskSpaceCm', Number(e.target.value))} />
                                    <span className={styles.sliderValue}>{form.physical.deskSpaceCm} cm</span>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Result message */}
            {result && (
                <div className={`${styles.result} ${result.success ? styles.resultSuccess : styles.resultError}`}>
                    {result.success ? '✅ Perfil salvo com sucesso!' : `❌ ${result.error}`}
                </div>
            )}

            {/* Navigation buttons */}
            <div className={styles.navButtons}>
                <button className="btn btn-ghost" onClick={() => setStep(s => s - 1)} disabled={!canGoBack}>
                    ← Voltar
                </button>

                {isLastStep ? (
                    <button className="btn btn-primary btn-lg" onClick={handleSubmit} disabled={saving}>
                        {saving ? '⏳ Salvando...' : '💾 Salvar Perfil'}
                    </button>
                ) : (
                    <button className="btn btn-primary" onClick={() => setStep(s => s + 1)} disabled={!canGoNext}>
                        Próximo →
                    </button>
                )}
            </div>
        </div>
    );
}

'use client';

/**
 * ProsClient — Interactive client component for pro player comparison.
 * Features: your sens comparator, player cards with real flags, scope numbers.
 */

import { useState } from 'react';
import type { ProPlayer } from '@/game/pubg';
import { TEAM_SLUGS, getPlayerImageUrl as PLAYER_IMG, getTeamLogoUrl as TEAM_LOGO } from '@/game/pubg';
import styles from './pros.module.css';

interface ProsClientProps {
    players: ProPlayer[];
    stats: {
        totalPlayers: number;
        avgCmPer360: number;
        minCmPer360: number;
        maxCmPer360: number;
    };
}

const SCOPES = ['red-dot', '2x', '3x', '4x', '6x', '8x'] as const;

const FLAG_URL = (code: string) =>
    `https://flagcdn.com/24x18/${code.toLowerCase()}.png`;

export function ProsClient({ players, stats }: ProsClientProps) {
    const [userDpi, setUserDpi] = useState('');
    const [userSens, setUserSens] = useState('');
    const [roleFilter, setRoleFilter] = useState<string>('all');
    const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);

    const userCm360 = userDpi && userSens
        ? (2.54 * 360) / (Number(userDpi) * (Number(userSens) / 100))
        : null;

    const filteredPlayers = roleFilter === 'all'
        ? players
        : players.filter(p => p.role === roleFilter);

    const toggleSelect = (id: string) => {
        setSelectedPlayers(prev =>
            prev.includes(id)
                ? prev.filter(p => p !== id)
                : prev.length < 2
                    ? [...prev, id]
                    : [prev[1]!, id]
        );
    };

    const compareMode = selectedPlayers.length === 2;
    const compPlayers = compareMode
        ? selectedPlayers.map(id => players.find(p => p.id === id)!).filter(Boolean)
        : [];

    return (
        <>
            {/* ─── Your Sens Comparator ─── */}
            <section className={styles.comparator}>
                <div className={styles.comparatorInner}>
                    <div className={styles.comparatorLeft}>
                        <h2 className={styles.comparatorTitle}>Compare sua Sensibilidade</h2>
                        <p className={styles.comparatorDesc}>
                            Digite seu DPI e sensibilidade in-game para ver como você se compara com os pros.
                        </p>
                    </div>
                    <div className={styles.comparatorInputs}>
                        <div className={styles.inputGroup}>
                            <label className={styles.inputLabel}>DPI</label>
                            <input
                                type="number"
                                className={styles.input}
                                placeholder="800"
                                value={userDpi}
                                onChange={e => setUserDpi(e.target.value)}
                            />
                        </div>
                        <div className={styles.inputGroup}>
                            <label className={styles.inputLabel}>In-Game Sens</label>
                            <input
                                type="number"
                                className={styles.input}
                                placeholder="45"
                                value={userSens}
                                onChange={e => setUserSens(e.target.value)}
                            />
                        </div>
                        {userCm360 !== null && (
                            <div className={styles.userResult}>
                                <span className={styles.userResultLabel}>Seu cm/360°</span>
                                <span className={styles.userResultValue}>{userCm360.toFixed(1)}</span>
                                <span className={styles.userResultCompare}>
                                    {userCm360 < stats.avgCmPer360
                                        ? `${(stats.avgCmPer360 - userCm360).toFixed(1)}cm mais rápido que a média`
                                        : userCm360 > stats.avgCmPer360
                                            ? `${(userCm360 - stats.avgCmPer360).toFixed(1)}cm mais lento que a média`
                                            : 'Exatamente na média dos pros!'}
                                </span>
                            </div>
                        )}
                    </div>
                </div>
            </section>

            {/* ─── Compare 2 Players Side by Side ─── */}
            {compareMode && (
                <section className={styles.compareSection}>
                    <div className={styles.sectionHeader}>
                        <h2 className={styles.sectionTitle}>⚔️ Comparação</h2>
                        <button className={styles.clearBtn} onClick={() => setSelectedPlayers([])}>
                            Limpar
                        </button>
                    </div>
                    <div className={styles.compareGrid}>
                        {compPlayers.map(player => (
                            <div key={player.id} className={styles.compareCard}>
                                <div className={styles.compareHeader}>
                                    <div className={styles.comparePhotoWrapper}>
                                        <img src={PLAYER_IMG(player.name)} alt={player.name} className={styles.playerPhoto} onError={(e) => { e.currentTarget.style.display = 'none'; }} referrerPolicy="no-referrer" />
                                    </div>
                                    <div className={styles.compareNameWrapper}>
                                        <img src={FLAG_URL(player.countryCode)} alt={player.countryCode} className={styles.flagImg} />
                                        <strong>{player.name}</strong>
                                    </div>
                                    {TEAM_LOGO(player.team) ? (
                                        <img src={TEAM_LOGO(player.team)!} alt={player.team} className={styles.compareTeamLogo} onError={(e) => { e.currentTarget.style.display = 'none'; }} title={player.team} referrerPolicy="no-referrer" />
                                    ) : (
                                        <span className={styles.compareTeam}>{player.team}</span>
                                    )}
                                </div>
                                <div className={styles.compareStats}>
                                    <div className={styles.compareStat}>
                                        <span className={styles.compareStatLabel}>cm/360°</span>
                                        <span className={styles.compareStatVal}>{player.cmPer360.toFixed(1)}</span>
                                    </div>
                                    <div className={styles.compareStat}>
                                        <span className={styles.compareStatLabel}>DPI</span>
                                        <span className={styles.compareStatVal}>{player.dpi}</span>
                                    </div>
                                    <div className={styles.compareStat}>
                                        <span className={styles.compareStatLabel}>Sens</span>
                                        <span className={styles.compareStatVal}>{player.inGameSens}</span>
                                    </div>
                                    <div className={styles.compareStat}>
                                        <span className={styles.compareStatLabel}>Mouse</span>
                                        <span className={styles.compareStatVal}>{player.mouse}</span>
                                    </div>
                                    <div className={styles.compareStat}>
                                        <span className={styles.compareStatLabel}>Grip</span>
                                        <span className={styles.compareStatVal}>{player.gripStyle}</span>
                                    </div>
                                </div>
                                <div className={styles.compareScopeTitle}>Scope Sensitivity</div>
                                {SCOPES.map(scope => (
                                    <div key={scope} className={styles.compareScopeRow}>
                                        <span className={styles.compareScopeLabel}>{scope}</span>
                                        <div className={styles.compareScopeBar}>
                                            <div
                                                className={styles.compareScopeBarFill}
                                                style={{ width: `${((player.scopeSens[scope] ?? 0) / 70) * 100}%` }}
                                            />
                                        </div>
                                        <span className={styles.compareScopeVal}>{player.scopeSens[scope] ?? '—'}</span>
                                    </div>
                                ))}
                            </div>
                        ))}
                    </div>
                </section>
            )}

            {/* ─── Filter + Player Grid ─── */}
            <section className={styles.section}>
                <div className={styles.sectionHeader}>
