import type { Diagnosis, CoachFeedback } from '@/types/engine';

// ═══════════════════════════════════════════
// PUBG Mechanics Constants
// ═══════════════════════════════════════════

const ATTACHMENTS = {
    vertical: { name: 'Vertical Grip', bonus: 'Reduz o recuo vertical em 15%. Ideal para quem tem dificuldades com pulldown.' },
    half: { name: 'Halfgrip', bonus: 'Reduz recuo vertical e horizontal em 8%, aumenta estabilidade. Melhor custo-benefício para sprays longos.' },
    angled: { name: 'Angled Grip', bonus: 'Reduz recuo horizontal em 15% e aumenta velocidade de ADS. Essencial para corrigir Drifts laterais.' },
    thumb: { name: 'Thumb Grip', bonus: 'Aumenta muito a velocidade de ADS e reduz levemente o recuo vertical inicial.' },
    lightweight: { name: 'Lightweight Grip', bonus: 'Reduz o "kick" do primeiro tiro e melhora a recuperação de mira. Ótimo para Taps e Rajadas.' },
    compensator: { name: 'Compensador', bonus: 'O item mais importante. Reduz o padrão de recuo em 25%.' },
} as const;

const DRILLS: Record<string, string> = {
    overpull: '**O Drill da Janela (30m)**: Vá ao Training Mode e escolha uma janela pequena. Faça sprays de 10 balas focando em manter TODO o spray dentro do buraco, sem deixar a mira descer. Se a mira descer, sua mão está sendo "pesada" demais.',
    underpull: '**Drill de Pulldown Gradual**: Atire em uma parede limpa a 50m. Tente fazer um "ponto" de impactos. Se o spray subir, force o mouse para baixo de forma contínua, não apenas no início.',
    late_compensation: '**The Flash Pull**: Foque no SOM do primeiro tiro. O movimento de descida do mouse deve iniciar EXATAMENTE junto com o áudio do disparo. Pratique sprays de 3 balas resetando a mira rapidamente.',
    excessive_jitter: '**Drill Vertical Puro**: Faça sprays ignorando o horizontal. Deixe a mira balançar para os lados, mas mantenha a altura PERFEITA. Quando o vertical estiver automático, comece a pinçar o horizontal levemente.',
    horizontal_drift: '**Linha de Tracejo**: Siga uma linha vertical na parede (como a quina de um prédio) enquanto faz o spray. Se a mira fugir da linha para o mesmo lado sempre, ajuste a posição do seu braço/mousepad.',
    inconsistency: '**Drill dos 20 Sprays**: Faça 20 sprays na mesma parede. Eles devem ser gêmeos. Se cada um for diferente, foque em relaxar o braço e repetir exatamente o mesmo movimento muscular.',
};

// ═══════════════════════════════════════════
// Adaptation Time Estimator
// ═══════════════════════════════════════════

function estimateAdaptationDays(severity: number): number {
    if (severity >= 5) return 7;
    if (severity >= 4) return 5;
    if (severity >= 3) return 3;
    return 1;
}

// ═══════════════════════════════════════════
// Main: Generate Coaching
// ═══════════════════════════════════════════

export function generateCoaching(diagnoses: readonly Diagnosis[]): CoachFeedback[] {
    return diagnoses.map((diagnosis): CoachFeedback => {
        let whatToAdjust = diagnosis.remediation;
        let whyItHappens = diagnosis.cause;

        // Injetar recomendações de attachments específicas baseadas no diagnóstico
        if (diagnosis.type === 'overpull') {
            whatToAdjust += ` Dica: Experimente usar o ${ATTACHMENTS.lightweight.name} para suavizar o kick inicial.`;
        } else if (diagnosis.type === 'underpull') {
            whatToAdjust += ` Dica: O ${ATTACHMENTS.vertical.name} e o ${ATTACHMENTS.compensator.name} são obrigatórios para seu caso.`;
        } else if (diagnosis.type === 'horizontal_drift' || diagnosis.type === 'excessive_jitter') {
            whatToAdjust += ` Dica: O ${ATTACHMENTS.angled.name} ou ${ATTACHMENTS.half.name} ajudarão a conter a oscilação lateral.`;
        }

        // Dica de Stance (Matemática do PUBG)
        if (diagnosis.severity >= 3) {
            whatToAdjust += ` Lembre-se: Agachar (Crouch) reduz o recuo em cerca de 20%. Use isso a seu favor em sprays longos.`;
        }

        return {
            diagnosis,
            whatIsWrong: diagnosis.description,
            whyItHappens,
            whatToAdjust,
            howToTest: DRILLS[diagnosis.type] ?? 'Pratique no Training Mode focando na consistência mecânica.',
            adaptationTimeDays: estimateAdaptationDays(diagnosis.severity),
        };
    });
}

/**
 * Diagnostic Engine — 6 classificações automáticas de problemas.
 *
 * 1. Overpull — compensação vertical excessiva
 * 2. Underpull — compensação vertical insuficiente
 * 3. Late Compensation — demora para reagir ao recoil
 * 4. Excessive Jitter — tremor horizontal excessivo
 * 5. Horizontal Drift — tendência direcional
 * 6. Inconsistency — variação alta entre segmentos
 */

import type {
    SprayMetrics,
    Diagnosis,
    OverpullDiagnosis,
    UnderpullDiagnosis,
    LateCompensationDiagnosis,
    ExcessiveJitterDiagnosis,
    HorizontalDriftDiagnosis,
    InconsistencyDiagnosis,
    Severity,
} from '@/types/engine';
import { asMilliseconds, asScore } from '@/types/branded';
import type { WeaponCategory } from '@/game/pubg/weapon-data';
import { getJitterThreshold } from '@/game/pubg/weapon-data';

// ═══════════════════════════════════════════
// Severity Helpers
// ═══════════════════════════════════════════

function percentToSeverity(percent: number): Severity {
    if (percent < 10) return 1;
    if (percent < 20) return 2;
    if (percent < 35) return 3;
    if (percent < 50) return 4;
    return 5;
}

function scoreToSeverity(score: number): Severity {
    if (score >= 80) return 1;
    if (score >= 60) return 2;
    if (score >= 40) return 3;
    if (score >= 20) return 4;
    return 5;
}

// ═══════════════════════════════════════════
// Individual Diagnostics
// ═══════════════════════════════════════════

function diagnoseOverpull(metrics: SprayMetrics): OverpullDiagnosis | null {
    const vci = metrics.verticalControlIndex;
    if (vci <= 1.15) return null; // Dentro do aceitável

    const excess = Math.round((vci - 1) * 100);
    return {
        type: 'overpull',
        severity: percentToSeverity(excess),
        verticalControlIndex: vci,
        excessPercent: excess,
        description: `Você está puxando o mouse ${excess}% a mais do que o necessário para compensar o recoil.`,
        cause: 'Sensibilidade muito baixa ou movimento brusco demais ao compensar. Possível excesso de força no pulldown.',
        remediation: `Reduza a força do pulldown. Considere aumentar a sens vertical em ${Math.min(excess, 15)}% ou usar o multiplicador vertical.`,
    };
}

function diagnoseUnderpull(metrics: SprayMetrics): UnderpullDiagnosis | null {
    const vci = metrics.verticalControlIndex;
    if (vci >= 0.85) return null;

    const deficit = Math.round((1 - vci) * 100);
    return {
        type: 'underpull',
        severity: percentToSeverity(deficit),
        verticalControlIndex: vci,
        deficitPercent: deficit,
        description: `Compensação vertical ${deficit}% abaixo do ideal. O spray sobe mais do que deveria.`,
        cause: 'Sensibilidade muito alta ou pulldown insuficiente. Pode indicar falta de espaço no mousepad ou hábito de spray curto.',
        remediation: `Aumente a força do pulldown ou reduza a sens em ${Math.min(deficit, 15)}%. Verifique se tem espaço suficiente no mousepad.`,
    };
}

function diagnoseLateCompensation(metrics: SprayMetrics): LateCompensationDiagnosis | null {
    const responseMs = Number(metrics.initialRecoilResponseMs);
    const idealMs = 120; // ~4 frames a 30fps
    if (responseMs <= idealMs * 1.5) return null;

    const delay = responseMs - idealMs;
    return {
        type: 'late_compensation',
        severity: delay > 200 ? 5 : delay > 150 ? 4 : delay > 100 ? 3 : delay > 50 ? 2 : 1,
        responseTimeMs: metrics.initialRecoilResponseMs,
        idealResponseMs: asMilliseconds(idealMs),
        description: `Sua reação ao recoil leva ${Math.round(responseMs)}ms. Ideal: ~${idealMs}ms.`,
        cause: 'Tempo de reação ao recuo inicial está alto. Pode indicar falta de antecipação ou hesitação no início do spray.',
        remediation: 'Pratique iniciar a compensação ANTES ou junto com o primeiro tiro. Antecipe o recoil com base no padrão da arma.',
    };
}

function diagnoseExcessiveJitter(
    metrics: SprayMetrics,
    category: WeaponCategory
): ExcessiveJitterDiagnosis | null {
    const threshold = getJitterThreshold(category);
    const noise = metrics.horizontalNoiseIndex;
    if (noise <= threshold) return null;

    const excessRatio = noise / threshold;
    return {
        type: 'excessive_jitter',
        severity: excessRatio > 3 ? 5 : excessRatio > 2.5 ? 4 : excessRatio > 2 ? 3 : excessRatio > 1.5 ? 2 : 1,
        horizontalNoise: noise,
        threshold,
        description: `Ruído horizontal de ${noise.toFixed(1)} (limite: ${threshold}). Seu spray está "tremendo".`,
        cause: 'Micro-ajustes excessivos, tensão na mão, ou grip instável. Mousepad com atrito irregular também pode causar.',
        remediation: 'Relaxe o grip durante o spray. Use movimentos suaves e contínuos. Considere um mousepad de controle se estiver em speed pad.',
    };
}

function diagnoseHorizontalDrift(metrics: SprayMetrics): HorizontalDriftDiagnosis | null {
    const { direction, magnitude } = metrics.driftDirectionBias;
    if (direction === 'neutral' || magnitude < 1.0) return null;

    return {
        type: 'horizontal_drift',
        severity: magnitude > 4 ? 5 : magnitude > 3 ? 4 : magnitude > 2 ? 3 : magnitude > 1.5 ? 2 : 1,
        bias: metrics.driftDirectionBias,
        description: `Tendência de desvio para a ${direction === 'left' ? 'esquerda' : 'direita'} (magnitude: ${magnitude.toFixed(1)}px/frame).`,
        cause: `Posicionamento assimétrico do braço ou ângulo do mousepad. Hábito de tracking que influencia o spray.`,
        remediation: `Centralize o mousepad em relação ao ombro. Pratique spray em linha reta sem alvo para calibrar.`,
    };
}

function diagnoseInconsistency(metrics: SprayMetrics): InconsistencyDiagnosis | null {
    const score = Number(metrics.consistencyScore);
    if (score >= 65) return null;

    return {
        type: 'inconsistency',
        severity: scoreToSeverity(score),
        consistencyScore: metrics.consistencyScore,
        description: `Consistência de ${score.toFixed(0)}/100. Seu spray varia muito entre disparos.`,
        cause: 'Falta de memória muscular, fadiga, ou mudança de ritmo durante o spray. Sens instável entre sessões.',
        remediation: 'Pratique o mesmo padrão de spray 100+ vezes sem mudar configurações. Use o Training Mode do PUBG com a mesma arma.',
    };
}

// ═══════════════════════════════════════════
// Main: Run All Diagnostics
// ═══════════════════════════════════════════

export function runDiagnostics(
    metrics: SprayMetrics,
    weaponCategory: WeaponCategory
): Diagnosis[] {
    const diagnoses: Diagnosis[] = [];

    const overpull = diagnoseOverpull(metrics);
    if (overpull) diagnoses.push(overpull);

    const underpull = diagnoseUnderpull(metrics);
    if (underpull) diagnoses.push(underpull);

    const late = diagnoseLateCompensation(metrics);
    if (late) diagnoses.push(late);

    const jitter = diagnoseExcessiveJitter(metrics, weaponCategory);
    if (jitter) diagnoses.push(jitter);

    const drift = diagnoseHorizontalDrift(metrics);
    if (drift) diagnoses.push(drift);

    const inconsistency = diagnoseInconsistency(metrics);
    if (inconsistency) diagnoses.push(inconsistency);

    // Ordenar por severidade (maior primeiro)
    diagnoses.sort((a, b) => b.severity - a.severity);

    return diagnoses;
}

/**
 * Inventory Scanner — Detecta arma e acessórios via tela de Inventário (Tab).
 */

import type { ExtractedFrame } from './frame-extraction';

export interface InventoryScanResult {
    readonly found: boolean;
    readonly activeSlot: 1 | 2 | null;
    readonly weaponId?: string;
    readonly attachments?: {
        readonly scope?: string;
        readonly muzzle?: string;
        readonly grip?: string;
        readonly stock?: string;
    };
}

// ═══════════════════════════════════════════
// Regions (Normalized 1080p)
// ═══════════════════════════════════════════

const SLOT_1_REGION = { x: 1280, y: 220, w: 300, h: 320 };
const SLOT_2_REGION = { x: 1280, y: 560, w: 300, h: 320 };

/**
 * Calcula a luminosidade média de uma região.
 * Usado para detectar qual slot está destacado (ativo).
 */
function calculateRegionBrightness(frame: ExtractedFrame, x: number, y: number, w: number, h: number): number {
    const { width: fw, data } = frame.imageData;
    let total = 0;
    let count = 0;

    // Scale coordinates to actual frame size
    const scale = fw / 1920;
    const sx = Math.floor(x * scale);
    const sy = Math.floor(y * scale);
    const sw = Math.floor(w * scale);
    const sh = Math.floor(h * scale);

    for (let ty = sy; ty < sy + sh; ty++) {
        for (let tx = sx; tx < sx + sw; tx++) {
            const idx = (ty * fw + tx) * 4;
            if (data[idx] !== undefined) {
                // Luminance: 0.299R + 0.587G + 0.114B
                total += (data[idx]! * 0.299 + data[idx + 1]! * 0.587 + data[idx + 2]! * 0.114);
                count++;
            }
        }
    }

    return count > 0 ? total / count : 0;
}

/**
 * Procura pela tela de Inventário nos primeiros frames do clip.
 */
export function scanInventory(frames: readonly ExtractedFrame[]): InventoryScanResult {
    // 1. Procurar um frame que tenha o "Inventário" (baseado em contraste ou elementos fixos)
    // Por simplicidade na V1, assumimos que se a luminosidade média de certas áreas bater, o Tab está aberto.

    let bestFrame: ExtractedFrame | null = null;
    let bestInventoryScore = 0;

    // Scan first 30-60 frames (1-2 seconds)
    for (let i = 0; i < Math.min(frames.length, 60); i++) {
        const frame = frames[i]!;

        // No inventário do PUBG, o lado direito (arma) costuma ser muito mais escuro (transparente) 
        // ou ter elementos de UI específicos.
        // Aqui detectamos a "presença" comparando o brilho dos slots com um fundo esperado.
        const b1 = calculateRegionBrightness(frame, SLOT_1_REGION.x, SLOT_1_REGION.y, SLOT_1_REGION.w, SLOT_1_REGION.h);
        const b2 = calculateRegionBrightness(frame, SLOT_2_REGION.x, SLOT_2_REGION.y, SLOT_2_REGION.w, SLOT_2_REGION.h);

        // PUBG UI high-contrast detection logic goes here.
        // If one is significantly brighter/has the 'active' highlight.
        if (Math.abs(b1 - b2) > 15) {
            bestFrame = frame;
            bestInventoryScore = Math.abs(b1 - b2);
            break;
        }
    }

    if (!bestFrame) {
        return { found: false, activeSlot: null };
    }

    // 2. Determinar slot ativo
    const b1 = calculateRegionBrightness(bestFrame, SLOT_1_REGION.x, SLOT_1_REGION.y, SLOT_1_REGION.w, SLOT_1_REGION.h);
    const b2 = calculateRegionBrightness(bestFrame, SLOT_2_REGION.x, SLOT_2_REGION.y, SLOT_2_REGION.w, SLOT_2_REGION.h);

    const activeSlot = b1 > b2 ? 1 : 2;

    // 3. TODO: Template Matching para nomes de armas/ícones
    // Isso requer uma base de dados de templates que será implementada na sequência.

    return {
        found: true,
        activeSlot,
        // Fallback for demo
    };
}

/**
 * Sensitivity Engine — Recomendações de sensibilidade baseadas no hardware.
 * Gera 3 perfis (LOW, BALANCED, HIGH) com micro-ajustes 2-6%.
 * Prioriza controle vertical.
 */

import type {
    SprayMetrics,
    SensitivityProfile,
    SensitivityRecommendation,
    ScopeSensitivity,
    ProfileType,
    Diagnosis,
    PlayerHardwareProfile,
} from '@/types/engine';
import { asSensitivity, asCentimeters } from '@/types/branded';
import type { Sensitivity, Centimeters } from '@/types/branded';
import {
    calculateCmPer360,
    internalFromCmPer360,
    calculateEffectiveSensitivity,
    isSensViableForMousepad,
    SCOPES,
    type ScopeId,
} from '@/game/pubg';
import { internalToSlider } from '@/game/pubg/sens-math';

// ═══════════════════════════════════════════
// Base ranges por play style + grip
// ═══════════════════════════════════════════

interface SensRange {
    readonly minCm360: number;
    readonly maxCm360: number;
    readonly idealCm360: number;
}

function getBaseSensRange(
    playStyle: string,
    gripStyle: string
): SensRange {
    // Arm aimers = mais cm/360 (baixa sens), Wrist = menos cm/360 (alta sens)
    const styleBase: Record<string, SensRange> = {
        arm: { minCm360: 35, maxCm360: 60, idealCm360: 45 },
        wrist: { minCm360: 18, maxCm360: 35, idealCm360: 25 },
        hybrid: { minCm360: 25, maxCm360: 45, idealCm360: 35 },
    };

    const base = styleBase[playStyle] ?? styleBase['hybrid']!;

    // Fingertip/claw = pode usar sens um pouco mais alta
    if (gripStyle === 'fingertip') {
        return { minCm360: base.minCm360 - 3, maxCm360: base.maxCm360 - 3, idealCm360: base.idealCm360 - 2 };
    }
    if (gripStyle === 'palm') {
        return { minCm360: base.minCm360 + 2, maxCm360: base.maxCm360 + 2, idealCm360: base.idealCm360 + 2 };
    }

    return base;
}

// ═══════════════════════════════════════════
// Adjust for diagnostics
// ═══════════════════════════════════════════

function adjustForDiagnostics(
    idealCm360: number,
    diagnoses: readonly Diagnosis[],
    metrics: SprayMetrics // Pass metrics to check phases
): number {
    let adjusted = idealCm360;

    // Usar burstVCI (balas 1-10) como peso principal (80%) se disponível
    const controlIndex = metrics.burstVCI !== undefined ? metrics.burstVCI : metrics.verticalControlIndex;

    for (const d of diagnoses) {
        switch (d.type) {
            case 'overpull':
                // Se o burstVCI confirmar overpull, o ajuste é mais agressivo
                const factor = controlIndex > 1.2 ? 0.05 : 0.03;
                adjusted -= adjusted * factor;
                break;
            case 'underpull':
                const uFactor = controlIndex < 0.8 ? 0.05 : 0.03;
                adjusted += adjusted * uFactor;
                break;
            case 'excessive_jitter':
                adjusted += adjusted * 0.04;
                break;
            case 'horizontal_drift':
                adjusted += adjusted * 0.02;
                break;
        }
    }

    return adjusted;
}

// ═══════════════════════════════════════════
// Build Profile
// ═══════════════════════════════════════════

function buildProfile(
    type: ProfileType,
    targetCm360: number,
    dpi: number,
    currentScopeSens: Record<string, number>
): SensitivityProfile {
    const internalMultiplier = internalFromCmPer360(dpi, targetCm360);
    const generalSlider = internalToSlider(internalMultiplier);
    const adsSlider = generalSlider; // PUBG baseline: ADS usually matches General

    // Calculate per-scope sensitivities
    const scopeEntries: ScopeSensitivity[] = (Object.keys(SCOPES) as ScopeId[])
        .filter(id => id !== 'hip')
        .map(scopeId => {
            const scope = SCOPES[scopeId];
            const current = currentScopeSens[scopeId] ?? 50;

            // Recomendamos que cada mira mantenha a mesma "física" do generalSlider
            // No PUBG, se você quer que 8x sinta igual a 1x (focal scaling), 
            // você geralmente mantém os sliders próximos se a engine for linear, 
            // mas como o PUBG tem multipliers internos, o ideal é o 1:1 físico.
            const recommended = generalSlider;

            return {
                scopeName: scope.name,
                current: asSensitivity(current),
                recommended: asSensitivity(recommended),
                changePercent: Math.round(((recommended - current) / Math.max(current, 1)) * 100),
            };
        });

    const labels: Record<ProfileType, { label: string; description: string }> = {
        low: {
            label: 'Baixa (Máx. Controle)',
            description: 'Maior cm/360°. Ideal para sprays longos e flicks precisos. Requer mais espaço no mousepad.',
        },
        balanced: {
            label: 'Balanceada',
            description: 'Equilíbrio entre controle e velocidade. Recomendado para a maioria dos jogadores.',
        },
        high: {
            label: 'Alta (Máx. Velocidade)',
            description: 'Menor cm/360°. Ideal para CQB e rotações rápidas. Menos controle em sprays longos.',
        },
    };

    const { label, description } = labels[type];

    return {
        type,
        label,
        description,
        general: asSensitivity(generalSlider),
        ads: asSensitivity(adsSlider),
        scopes: scopeEntries,
        cmPer360: asCentimeters(Math.round(targetCm360 * 100) / 100),
    };
}

// ═══════════════════════════════════════════
// Main: Generate Sensitivity Recommendation
// ═══════════════════════════════════════════

export function generateSensitivityRecommendation(
    metrics: SprayMetrics,
    diagnoses: readonly Diagnosis[],
    dpi: number,
    playStyle: string,
    gripStyle: string,
    mousepadWidthCm: number,
    currentScopeSens: Record<string, number>,
    currentVSM: number = 1.0
): SensitivityRecommendation {
    // 1. Get base range
    const range = getBaseSensRange(playStyle, gripStyle);

    // 2. Adjust ideal based on diagnostics + phase weighting
    const adjustedIdeal = adjustForDiagnostics(range.idealCm360, diagnoses, metrics);

    // 3. Clamp to viable range (mousepad-aware)
    const minViable = isSensViableForMousepad(range.minCm360, mousepadWidthCm) ? range.minCm360 : adjustedIdeal * 0.8;
    const maxViable = range.maxCm360;

    // 4. Generate 3 profiles with ~5% spread
    const lowCm360 = Math.min(adjustedIdeal * 1.06, maxViable);
    const balancedCm360 = adjustedIdeal;
    const highCm360 = Math.max(adjustedIdeal * 0.94, minViable);

    const profiles: [SensitivityProfile, SensitivityProfile, SensitivityProfile] = [
        buildProfile('low', lowCm360, dpi, currentScopeSens),
        buildProfile('balanced', balancedCm360, dpi, currentScopeSens),
        buildProfile('high', highCm360, dpi, currentScopeSens),
    ];

    // 5. Choose recommended profile based on dominant diagnosis
    let recommended: ProfileType = 'balanced';
    const dominant = diagnoses[0]; // Highest severity
    if (dominant) {
        if (dominant.type === 'overpull') {
            recommended = 'high';
        } else if (dominant.type === 'underpull') {
            recommended = 'low';
        }
    }

    // 6. Calculate Bi-directional VSM Adjustment
    // Se BurstVCI > 1.1 ou < 0.9, sugerimos mudar o VSM
    const burstVCI = metrics.burstVCI ?? metrics.verticalControlIndex;
    let suggestedVSM: number | undefined;

    if (burstVCI > 1.05 || burstVCI < 0.95) {
        // target_vsm = current_vsm / vci
        suggestedVSM = Number((currentVSM / burstVCI).toFixed(2));
        // Clamp entre 0.7 e 2.0 (limites razoáveis do PUBG)
        suggestedVSM = Math.max(0.7, Math.min(2.0, suggestedVSM));
    }

    // 7. Reasoning
    const reasoningParts: string[] = [
        `Fase Burst: VCI ${burstVCI.toFixed(2)}`,
        `Estilo ${playStyle}, Grip ${gripStyle}`,
    ];
    if (dominant) {
        reasoningParts.push(`foco em ${dominant.type}`);
    }
    const reasoning = reasoningParts.join(', ') + '.';
    return {
        profiles,
        recommended,
        reasoning,
        ...(suggestedVSM !== undefined ? { suggestedVSM } : {})
    };
}

/**
 * Spray Metrics Calculator — Calcula as 6 métricas obrigatórias do spray.
 *
 * 1. Spray Stability Score (0-100)
 * 2. Vertical Control Index (0-1, ideal = 1.0)
 * 3. Horizontal Noise Index (0+)
 * 4. Initial Recoil Response Time (ms)
 * 5. Drift Direction Bias
 * 6. Consistency Score (0-100)
 */

import type {
    TrackingPoint,
    DisplacementVector,
    SprayTrajectory,
    SprayMetrics,
    DriftBias,
} from '@/types/engine';
import type { Pixels, Milliseconds, Score } from '@/types/branded';
import { asMilliseconds, asScore, asPixels } from '@/types/branded';
import type { TrackingResult } from './crosshair-tracking';
import type { WeaponData, RecoilVector } from '@/game/pubg/weapon-data';

// ═══════════════════════════════════════════
// FPS-to-RPM Resampling Engine
// ═══════════════════════════════════════════

/**
 * Realinha matematicamente os frames de vídeo (30fps/60fps) com o Fire Rate (RPM) da arma.
 * Isso garante que o cálculo de recoil bata perfeitamente com a compensação esperada.
 */
function resampleToFireRate(points: readonly TrackingPoint[], msPerShot: number): TrackingPoint[] {
    if (points.length < 2) return [...points];

    const resampled: TrackingPoint[] = [];
    const firstTime = Number(points[0]!.timestamp);
    const lastTime = Number(points[points.length - 1]!.timestamp);

    let targetTime = firstTime;

    // Interpola a mira (X,Y) exatamente no milissegundo em que cada tiro acontece
    while (targetTime <= lastTime) {
        let leftIdx = 0;
        let rightIdx = points.length - 1;

        for (let i = 0; i < points.length - 1; i++) {
            if (Number(points[i]!.timestamp) <= targetTime && Number(points[i + 1]!.timestamp) >= targetTime) {
                leftIdx = i;
                rightIdx = i + 1;
                break;
            }
        }

        const left = points[leftIdx]!;
        const right = points[rightIdx]!;

        const t0 = Number(left.timestamp);
        const t1 = Number(right.timestamp);

        let ratio = 0;
        if (t1 > t0) {
            ratio = (targetTime - t0) / (t1 - t0);
        }

        const x = Number(left.x) + (Number(right.x) - Number(left.x)) * ratio;
        const y = Number(left.y) + (Number(right.y) - Number(left.y)) * ratio;

        resampled.push({
            frame: resampled.length, // Linear index representing the exact bullet number
            x: asPixels(x),
            y: asPixels(y),
            timestamp: asMilliseconds(targetTime),
            confidence: left.confidence,
        });

        targetTime += msPerShot;
    }

    return resampled;
}

// ═══════════════════════════════════════════
// Trajectory Builder
// ═══════════════════════════════════════════

/**
 * Converte TrackingPoints em displacements (variação entre frames consecutivos).
 */
export function buildDisplacements(
    points: readonly TrackingPoint[]
): DisplacementVector[] {
    const displacements: DisplacementVector[] = [];

    for (let i = 1; i < points.length; i++) {
        const prev = points[i - 1];
        const curr = points[i];
        if (!prev || !curr) continue;

        displacements.push({
            dx: Number(curr.x) - Number(prev.x),
            dy: Number(curr.y) - Number(prev.y),
            timestamp: curr.timestamp,
            shotIndex: i - 1,
        });
    }

    return displacements;
}

/**
 * Removes 1-frame jitter/spikes caused by video compression and muzzle flash.
 * Applies a Simple Moving Average (SMA) but rejects low-confidence outlier frames.
 */
function smoothTrackingSignal(points: readonly TrackingPoint[], windowSize: number = 3): TrackingPoint[] {
    if (points.length < windowSize) return [...points];

    const smoothed: TrackingPoint[] = [];
    const halfWindow = Math.floor(windowSize / 2);

    for (let i = 0; i < points.length; i++) {
        let sumX = 0;
        let sumY = 0;
        let count = 0;

        for (let j = -halfWindow; j <= halfWindow; j++) {
            const idx = i + j;
            if (idx >= 0 && idx < points.length) {
                const pt = points[idx];
                // Reject low confidence frames (e.g. muzzle flash occlusion)
                if (pt && pt.confidence >= 0.7) {
                    sumX += Number(pt.x);
                    sumY += Number(pt.y);
                    count++;
                }
            }
        }

        const orig = points[i]!;
        if (count > 0) {
            smoothed.push({
                ...orig,
                x: asPixels(sumX / count),
                y: asPixels(sumY / count),
            });
        } else {
            smoothed.push({ ...orig });
        }
    }
    return smoothed;
}

/**
 * Constrói a trajetória completa do spray após resample para o BPM (RPM) da arma.
 */
export function buildTrajectory(
    tracking: TrackingResult,
    weapon: WeaponData
): SprayTrajectory {
    // 0. Smooth tracking signal -> Reject low confidence + moving average
    const smoothedRawPoints = smoothTrackingSignal(tracking.points);

    // 1. Resample dos frames crus do Canvas para Tiros da Arma (interpolação P(t))
    const resampledPoints = resampleToFireRate(smoothedRawPoints, weapon.msPerShot);

    // 2. Transforma as posições em deltas entre tiros
    const displacements = buildDisplacements(resampledPoints);

    const firstPoint = resampledPoints[0];
    const lastPoint = resampledPoints[resampledPoints.length - 1];

    return {
        points: resampledPoints, // save the resampled points
        displacements,
        totalFrames: resampledPoints.length,
        durationMs: asMilliseconds(
            (lastPoint && firstPoint)
                ? Number(lastPoint.timestamp) - Number(firstPoint.timestamp)
                : 0
        ),
        weaponId: weapon.id,
    };
}

// ═══════════════════════════════════════════
// Metric 1: Spray Stability Score (0-100)
// ═══════════════════════════════════════════

/**
 * Estabilidade geral com base no desvio padrão do spray.
 * Score alto = spray concentrado em uma área pequena.
 */
function calculateStability(displacements: readonly DisplacementVector[]): Score {
    if (displacements.length === 0) return asScore(0);

    // Calcular desvio padrão das distâncias do centróide
    const meanDx = displacements.reduce((a, d) => a + d.dx, 0) / displacements.length;
    const meanDy = displacements.reduce((a, d) => a + d.dy, 0) / displacements.length;

    const variance = displacements.reduce((sum, d) => {
        return sum + (d.dx - meanDx) ** 2 + (d.dy - meanDy) ** 2;
    }, 0) / displacements.length;

    const stdDev = Math.sqrt(variance);

    // Normalizar: stdDev ~0 = 100, stdDev ~30 = 0
    const normalized = Math.max(0, 100 - (stdDev / 30) * 100);
    return asScore(normalized);
}

// ═══════════════════════════════════════════
// Metric 2: Vertical Control Index (0-1)
// ═══════════════════════════════════════════

/**
 * Mede quão bem o jogador compensa o recoil vertical.
 * Compara o deslocamento vertical observado com o esperado.
 * 
 * 1.0 = compensação perfeita
 * <1.0 = underpull (não puxa o suficiente)
 * >1.0 = overpull (puxa demais)
 */
function calculateVerticalControl(
    displacements: readonly DisplacementVector[],
    weaponRecoil: readonly RecoilVector[],
    pixelToDegree: number
): number {
    if (displacements.length === 0 || weaponRecoil.length === 0) return 1.0;

    // Soma total do recoil esperado (vertical) em Graus
    const expectedVertical = weaponRecoil.reduce((sum, r) => sum + r.pitch, 0);
    if (expectedVertical === 0) return 1.0;

    // Soma total do deslocamento vertical observado convertido para Graus
    const observedVertical = displacements.reduce((sum, d) => sum + (d.dy * pixelToDegree), 0);

    // Se observado é próximo de 0, jogador compensou perfeitamente.
    // Ratio: (expectedVertical - observedVertical) / expectedVertical
    const compensated = expectedVertical - observedVertical;
    const ratio = compensated / expectedVertical;

    // Clamp entre 0 e 2 (0 = nenhuma comp., 1 = perfeita, 2 = overpull)
    return Math.max(0, Math.min(2, ratio));
}

// ═══════════════════════════════════════════
// Metric 3: Horizontal Noise Index
// ═══════════════════════════════════════════

/**
 * Desvio padrão do movimento horizontal.
 * Valor baixo = spray horizontal limpo.
 */
function calculateHorizontalNoise(
    displacements: readonly DisplacementVector[],
    pixelToDegree: number
): number {
    if (displacements.length === 0) return 0;

    // Converte os pixels registrados no video em in-game degrees (Yaw)
    const yawValues = displacements.map(d => d.dx * pixelToDegree);
    const mean = yawValues.reduce((a, b) => a + b, 0) / yawValues.length;
    const variance = yawValues.reduce((sum, yaw) => sum + (yaw - mean) ** 2, 0) / yawValues.length;

    return Math.round(Math.sqrt(variance) * 1000) / 1000;
}

// ═══════════════════════════════════════════
// Metric 4: Initial Recoil Response Time (ms)
// ═══════════════════════════════════════════

/**
 * Tempo até o jogador começar a compensar o recoil.
 * Medido como o tempo até o primeiro movimento oposto ao recoil.
 */
function calculateRecoilResponseTime(
    displacements: readonly DisplacementVector[],
    firstTimestamp: number
): Milliseconds {
    if (displacements.length === 0) return asMilliseconds(0);

    // Procurar o primeiro frame onde dy é negativo (jogador puxou pra baixo)
    for (let i = 0; i < displacements.length; i++) {
        const d = displacements[i];
        if (d && d.dy < -1) { // threshold: pelo menos -1px
            return asMilliseconds(Number(d.timestamp) - firstTimestamp);
        }
    }

    // Nunca compensou — retorna duração total
    const lastD = displacements[displacements.length - 1];
    return asMilliseconds(lastD ? Number(lastD.timestamp) - firstTimestamp : 0);
}

// ═══════════════════════════════════════════
// Metric 5: Drift Direction Bias
// ═══════════════════════════════════════════

/**
 * Detecta tendência de desvio horizontal.
 * Se o acumulado horizontal pende para um lado, há drift bias.
 */
function calculateDriftBias(
    displacements: readonly DisplacementVector[]
): DriftBias {
    if (displacements.length === 0) {
        return { direction: 'neutral', magnitude: 0 };
    }

    const totalDx = displacements.reduce((sum, d) => sum + d.dx, 0);
    const avgDx = totalDx / displacements.length;

    const THRESHOLD = 0.5; // pixels por frame

    let direction: 'left' | 'right' | 'neutral';
    if (avgDx < -THRESHOLD) {
        direction = 'left';
    } else if (avgDx > THRESHOLD) {
        direction = 'right';
    } else {
        direction = 'neutral';
    }

    return {
        direction,
        magnitude: Math.round(Math.abs(avgDx) * 100) / 100,
    };
}

// ═══════════════════════════════════════════
// Metric 6: Consistency Score (0-100)
// ═══════════════════════════════════════════

/**
 * Mede a consistência do spray comparando janelas de frames.
 * Score alto = cada segmento do spray é similar aos outros.
 */
function calculateConsistency(
    displacements: readonly DisplacementVector[]
): Score {
    if (displacements.length < 6) return asScore(50);

    // Dividir em 3 segmentos (Burst, Sustained, Fatigue) para checar a variação
    const segmentSize = Math.floor(displacements.length / 3);
    const segments = [
        displacements.slice(0, segmentSize),
        displacements.slice(segmentSize, segmentSize * 2),
        displacements.slice(segmentSize * 2, segmentSize * 3),
    ];

    // Calcular variância de cada segmento baseada no DY (controle vertical)
    const segmentVariances = segments.map(seg => {
        if (seg.length === 0) return 0;
        const dys = seg.map(d => d.dy);
        const mean = dys.reduce((a, b) => a + b, 0) / dys.length;
        return dys.reduce((sum, dy) => sum + (dy - mean) ** 2, 0) / dys.length;
    });

    // Consistência = baixa variação entre as variâncias dos segmentos
    const meanVar = segmentVariances.reduce((a, b) => a + b, 0) / segmentVariances.length;
    const varOfVar = segmentVariances.reduce((sum, v) => sum + (v - meanVar) ** 2, 0) / segmentVariances.length;

    // Normalização Sigmóide para evitar que caia pra 0 com facilidade
    // Se a variação da variância for alta, o score cai, mas de forma mais suave
    const sensitivity = 0.5; // Ajuste para calibração
    const normalized = 100 / (1 + Math.exp(Math.sqrt(varOfVar) * sensitivity - 5));

    return asScore(Math.round(normalized));
}

// ═══════════════════════════════════════════
// Main: Calculate All Metrics
// ═══════════════════════════════════════════

export function calculateSprayMetrics(
    trajectory: SprayTrajectory,
    weapon: WeaponData,
    pixelToDegree: number = 0.046875 // Default 1080p 90 FOV
): SprayMetrics {
    const { displacements, points } = trajectory;
    const firstTimestamp = points.length > 0 ? Number(points[0]!.timestamp) : 0;

    // Phases definition
    const burstDisplacements = displacements.slice(0, 10);
    const sustainedDisplacements = displacements.slice(10, 20);
    const fatigueDisplacements = displacements.slice(20);

    const burstRecoil = weapon.recoilPattern.slice(0, 10);
    const sustainedRecoil = weapon.recoilPattern.slice(10, 20);
    const fatigueRecoil = weapon.recoilPattern.slice(20, displacements.length);

    return {
        stabilityScore: calculateStability(displacements),
        verticalControlIndex: calculateVerticalControl(displacements, weapon.recoilPattern, pixelToDegree),
        horizontalNoiseIndex: calculateHorizontalNoise(displacements, pixelToDegree),
        initialRecoilResponseMs: calculateRecoilResponseTime(displacements, firstTimestamp),
        driftDirectionBias: calculateDriftBias(displacements),
        consistencyScore: calculateConsistency(displacements),
        // Phase-based metrics
        burstVCI: calculateVerticalControl(burstDisplacements, burstRecoil, pixelToDegree),
        sustainedVCI: calculateVerticalControl(sustainedDisplacements, sustainedRecoil, pixelToDegree),
        fatigueVCI: calculateVerticalControl(fatigueDisplacements, fatigueRecoil, pixelToDegree),
        burstHNI: calculateHorizontalNoise(burstDisplacements, pixelToDegree),
        sustainedHNI: calculateHorizontalNoise(sustainedDisplacements, pixelToDegree),
        fatigueHNI: calculateHorizontalNoise(fatigueDisplacements, pixelToDegree),
    };
}

/**
 * Database Schema — Drizzle ORM schema para Neon PostgreSQL.
 * Todas as tabelas do sistema com tipos inferidos automaticamente.
 */

import {
    pgTable,
    text,
    timestamp,
    integer,
    boolean,
    real,
    jsonb,
    uuid,
    primaryKey,
} from 'drizzle-orm/pg-core';
import type { AdapterAccount } from '@auth/core/adapters';

// ═══════════════════════════════════════════
// Auth.js Tables (NextAuth adapter)
// ═══════════════════════════════════════════

export const users = pgTable('users', {
    id: uuid('id').defaultRandom().primaryKey(),
    name: text('name'),
    email: text('email').unique(),
    emailVerified: timestamp('email_verified', { mode: 'date' }),
    image: text('image'),
    language: text('language').default('pt-BR').notNull(),
    createdAt: timestamp('created_at', { mode: 'date' }).defaultNow().notNull(),
    updatedAt: timestamp('updated_at', { mode: 'date' }).defaultNow().notNull(),
});

export const accounts = pgTable(
    'accounts',
    {
        userId: uuid('user_id')
            .notNull()
            .references(() => users.id, { onDelete: 'cascade' }),
        type: text('type').$type<AdapterAccount['type']>().notNull(),
        provider: text('provider').notNull(),
        providerAccountId: text('provider_account_id').notNull(),
        refresh_token: text('refresh_token'),
        access_token: text('access_token'),
        expires_at: integer('expires_at'),
        token_type: text('token_type'),
        scope: text('scope'),
        id_token: text('id_token'),
        session_state: text('session_state'),
    },
    (account) => [
        primaryKey({ columns: [account.provider, account.providerAccountId] }),
    ]
);

export const sessions = pgTable('sessions', {
    sessionToken: text('session_token').primaryKey(),
    userId: uuid('user_id')
        .notNull()
        .references(() => users.id, { onDelete: 'cascade' }),
    expires: timestamp('expires', { mode: 'date' }).notNull(),
});

export const verificationTokens = pgTable(
    'verification_tokens',
    {
        identifier: text('identifier').notNull(),
        token: text('token').notNull(),
        expires: timestamp('expires', { mode: 'date' }).notNull(),
    },
    (vt) => [primaryKey({ columns: [vt.identifier, vt.token] })]
);

// ═══════════════════════════════════════════
// Player Profiles
// ═══════════════════════════════════════════

export const playerProfiles = pgTable('player_profiles', {
    id: uuid('id').defaultRandom().primaryKey(),
    userId: uuid('user_id')
        .notNull()
        .unique()
        .references(() => users.id, { onDelete: 'cascade' }),

    // Mouse
    mouseModel: text('mouse_model').notNull(),
    mouseSensor: text('mouse_sensor').notNull(),
    mouseDpi: integer('mouse_dpi').notNull(),
    mousePollingRate: integer('mouse_polling_rate').notNull(),
    mouseWeight: real('mouse_weight').notNull(),
    mouseLod: real('mouse_lod').notNull(),

    // Mousepad
    mousepadModel: text('mousepad_model').notNull(),
    mousepadWidth: real('mousepad_width').notNull(),
    mousepadHeight: real('mousepad_height').notNull(),
    mousepadType: text('mousepad_type').notNull(), // speed | control | hybrid
    mousepadMaterial: text('mousepad_material').notNull(), // cloth | hard | glass

    // Style
    gripStyle: text('grip_style').notNull(), // palm | claw | fingertip | hybrid
    playStyle: text('play_style').notNull(), // arm | wrist | hybrid

    // Monitor
    monitorResolution: text('monitor_resolution').notNull(),
    monitorRefreshRate: integer('monitor_refresh_rate').notNull(),
    monitorPanel: text('monitor_panel').notNull(), // ips | tn | va

    // PUBG Settings
    generalSens: real('general_sens').notNull(),
    adsSens: real('ads_sens').notNull(),
